                deliveries[p] = int(q)
    elif file_path.endswith('key-value.txt'):
        for line in content.split('\n'):
            if line.startswith('PRODUCT:'):
                parts = line.split('|')
                p = parts[0].split(':')[1].strip()
                q = int(parts[1].split(':')[1].strip())
                deliveries[p] = q
    elif file_path.endswith('text-template.txt'):
        for line in content.split('\n'):
            if line:
                m = re.search(r'delivered (\d+) units of product (P_\d+)', line)
                if m:
                    deliveries[m.group(2)] = int(m.group(1))
    return deliveries

def parse_store_order(file_path):
    order = {}
    with open(file_path, 'r') as f:
        content = f.read().strip()
    if file_path.endswith('.json'):
        data = json.loads(content)
        for item in data['items']:
            order[item['prod_id']] = item['qty']
    elif file_path.endswith('table-csv.csv'):
        for line in content.split('\n')[1:]:
            if line:
                p, q = line.split(';')
                order[p] = int(q)
    elif file_path.endswith('key-value.txt'):
        for line in content.split('\n'):
            if line.startswith('RECEIVER:'):
                parts = line.split('|')
                p = parts[1].split(':')[1].strip()
                q = int(parts[2].split(':')[1].strip())
                order[p] = q
    elif file_path.endswith('text-template.txt'):
        for line in content.split('\n'):
            if line:
                m = re.search(r'deliver (\d+) units of product (P_\d+)', line)
                if m:
                    order[m.group(2)] = int(m.group(1))
    return order

wholesaler_inventory = {}
store_inventory = {f"S_{i}": {} for i in range(1, 11)}

# Product -> list of sets of suspect producers
suspects = defaultdict(list)

for day in range(1, 366):
    # 1. Supplier receipts
    supp_seq = []
    files = glob.glob(f'/app/raw_wholesaler_receipts/day_{day:03d}_PR_*_receipt.txt')
    for f in files:
        with open(f, 'r') as fh:
            content = fh.read()
            m1 = re.search(r'SUPPLIER_ID:\s*(PR_\d+)', content)
            m2 = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
            supp_seq.append((int(m2.group(1)), m1.group(1)))
    supp_seq.sort()

    for seq, supp_id in supp_seq:
        # Need to handle case where supplier receipt file might be missing? No, should exist.
        receipt_files = glob.glob(f'/app/raw_supplier_receipts/day_{day:03d}_{supp_id}_*')
        if receipt_files:
            deliveries = parse_supplier_receipt(receipt_files[0])
            for p, q in deliveries.items():
                if p not in wholesaler_inventory:
                    wholesaler_inventory[p] = []
                wholesaler_inventory[p].append([supp_id, q])

    # 2. Store orders
    store_seq = []
    files = glob.glob(f'/app/raw_wholesaler_store_receipts/day_{day:03d}_S_*_receipt.txt')
    for f in files:
        with open(f, 'r') as fh:
            content = fh.read()
            m1 = re.search(r'STORE_ID:\s*(S_\d+)', content)
            m2 = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
            m3 = re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)', content)
            # if total delivered is 0, we can skip ordering
            if int(m3.group(1)) > 0:
                store_seq.append((int(m2.group(1)), m1.group(1)))
    store_seq.sort()

    for seq, store_id in store_seq:
        order_files = glob.glob(f'/app/raw_orders/day_{day:03d}_{store_id}_*')
        if not order_files: continue
        order = parse_store_order(order_files[0])
        for p, req_q in order.items():
            if p not in store_inventory[store_id]:
                store_inventory[store_id][p] = []
            while req_q > 0 and p in wholesaler_inventory and len(wholesaler_inventory[p]) > 0:
                batch = wholesaler_inventory[p][0]
                if batch[1] <= req_q:
                    store_inventory[store_id][p].append([batch[0], batch[1]])
                    req_q -= batch[1]
                    wholesaler_inventory[p].pop(0)
                else:
                    store_inventory[store_id][p].append([batch[0], req_q])
                    batch[1] -= req_q
                    req_q = 0

    # 3. Consumer Sales
    day_sales = df[df.Day == day]

    consumed_today = defaultdict(lambda: defaultdict(set))

    for _, row in day_sales.iterrows():
        sold_qty = row['Sold_Quantity']
        store = row['Store_ID']
        p = row['Product_ID']

        while sold_qty > 0 and p in store_inventory[store] and len(store_inventory[store][p]) > 0:
            batch = store_inventory[store][p][0]
            consumed_today[store][p].add(batch[0])
            if batch[1] <= sold_qty:
                sold_qty -= batch[1]
                store_inventory[store][p].pop(0)
            else:
                batch[1] -= sold_qty
                sold_qty = 0

    # Check if any store consumed a bad batch today (based on drops on day+1)
    if day in drops_dict:
        for store, products in drops_dict[day].items():
            for p in products:
                if p in consumed_today[store]:
                    suspects[p].append(consumed_today[store][p])

# 3. Find confirmed offenders
confirmed = {}
for p in p_ids:
    if not suspects[p]:
        confirmed[p] = []
        continue

    # We can take the intersection of all suspect sets for this product!
    # Wait, what if there are multiple confirmed offenders for a product, and different ones caused different drops?
    # Then taking the intersection of ALL sets might be empty!
    # A better approach: A producer is confirmed if their presence can explain some drops, and there's no other explanation?
    # Or, maybe there's just a fixed set of bad producers, and whenever they are consumed, they ALWAYS cause a drop.
    # Let's count how many times a producer is in the suspect set.
    pass

with open('/tmp/suspects.json', 'w') as f:
    json.dump({k: [list(s) for s in v] for k, v in suspects.items()}, f)

