    elif file_path.endswith('table-csv.csv'):
        for line in content.split('\n')[1:]:
            if line: deliveries[line.split(';')[0]] = int(line.split(';')[1])
    elif file_path.endswith('key-value.txt'):
        for line in content.split('\n'):
            if line.startswith('PRODUCT:'):
                deliveries[line.split('|')[0].split(':')[1].strip()] = int(line.split('|')[1].split(':')[1].strip())
    elif file_path.endswith('text-template.txt'):
        for line in content.split('\n'):
            m = re.search(r'delivered (\d+) units of product (P_\d+)', line)
            if m: deliveries[m.group(2)] = int(m.group(1))
    return deliveries

def parse_store_order(file_path):
    order = {}
    with open(file_path, 'r') as f: content = f.read().strip()
    if file_path.endswith('.json'):
        for item in json.loads(content)['items']: order[item['prod_id']] = item['qty']
    elif file_path.endswith('table-csv.csv'):
        for line in content.split('\n')[1:]:
            if line: order[line.split(';')[0]] = int(line.split(';')[1])
    elif file_path.endswith('key-value.txt'):
        for line in content.split('\n'):
            if line.startswith('RECEIVER:'):
                order[line.split('|')[1].split(':')[1].strip()] = int(line.split('|')[2].split(':')[1].strip())
    elif file_path.endswith('text-template.txt'):
        for line in content.split('\n'):
            m = re.search(r'deliver (\d+) units of product (P_\d+)', line)
            if m: order[m.group(2)] = int(m.group(1))
    return order

wholesaler_inventory = {}
store_inventory = {f"S_{i}": {} for i in range(1, 11)}

all_consumptions = defaultdict(lambda: defaultdict(lambda: defaultdict(list)))

for day in range(1, 366):
    supp_seq = []
    for f in wr_map[day]:
        with open(f, 'r') as fh:
            content = fh.read()
            supp_seq.append((int(re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content).group(1)), re.search(r'SUPPLIER_ID:\s*(PR_\d+)', content).group(1)))
    supp_seq.sort()
    for seq, supp_id in supp_seq:
        if (day, supp_id) in sr_map:
            for p, q in parse_supplier_receipt(sr_map[(day, supp_id)]).items():
                if p not in wholesaler_inventory: wholesaler_inventory[p] = []
                wholesaler_inventory[p].append([supp_id, q])

    store_seq = []
    for f in wsr_map[day]:
        with open(f, 'r') as fh:
            content = fh.read()
            if int(re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)', content).group(1)) > 0:
                store_seq.append((int(re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content).group(1)), re.search(r'STORE_ID:\s*(S_\d+)', content).group(1)))
    store_seq.sort()
    for seq, store_id in store_seq:
        if (day, store_id) in order_map:
            for p, req_q in parse_store_order(order_map[(day, store_id)]).items():
                if p not in store_inventory[store_id]: store_inventory[store_id][p] = []
                while req_q > 0 and p in wholesaler_inventory and wholesaler_inventory[p]:
                    batch = wholesaler_inventory[p][0]
                    if batch[1] <= req_q:
                        store_inventory[store_id][p].append([batch[0], batch[1]])
                        req_q -= batch[1]
                        wholesaler_inventory[p].pop(0)
                    else:
                        store_inventory[store_id][p].append([batch[0], req_q])
                        batch[1] -= req_q
                        req_q = 0

    day_sales = df[df.Day == day]
    consumed_today = defaultdict(lambda: defaultdict(set))
    for _, row in day_sales.iterrows():
        sold_qty = row['Sold_Quantity']
        if sold_qty == 0: continue
        store = row['Store_ID']
        p = row['Product_ID']
        while sold_qty > 0 and p in store_inventory[store] and store_inventory[store][p]:
            batch = store_inventory[store][p][0]
            consumed_today[store][p].add(batch[0])
            if batch[1] <= sold_qty:
                sold_qty -= batch[1]
                store_inventory[store][p].pop(0)
            else:
                batch[1] -= sold_qty
                sold_qty = 0

    for store, p_dict in consumed_today.items():
        for p, prods in p_dict.items():
            all_consumptions[day][store][p] = list(prods)

with open('/tmp/consumptions.json', 'w') as f:
    json.dump(all_consumptions, f)
print("Consumptions saved!")
EOF
